import React, { useState } from 'react';
import { Link } from 'react-router-dom';
import { Home, Menu, X } from 'lucide-react';

export default function Navbar() {
  const [mobileMenuOpen, setMobileMenuOpen] = useState(false);

  return (
    <nav className="flex justify-between items-center h-14 py-4 bg-indigo-600 border border-zinc-800 text-white font-inter">
      <div className="flex items-center space-x-4 lg:space-x-6">
        <Link to="/" className="flex items-center space-x-2 text-indigo-400 hover:text-indigo-700">
          <img src="logo.png" alt="Luxury Getaway Logo" className="w-8 h-8 rounded-full" />
          <span className="text-lg font-bold">Luxury Getaway</span>
        </Link>
      </div>
      <div className="hidden lg:flex space-x-4 items-center">
        <Link to="/about" className="hover:text-indigo-700 transition-colors duration-200">About</Link>
        <Link to="/packages" className="hover:text-indigo-700 transition-colors duration-200">Packages</Link>
        <Link to="/book-now" className="bg-indigo-700 hover:bg-indigo-900 transition-colors duration-200 text-white px-4 py-2 rounded-md">Book Now</Link>
      </div>
      <button
        className="lg:hidden flex items-center justify-center w-8 h-8 rounded-full hover:bg-indigo-700 transition-colors duration-200"
        onClick={() => setMobileMenuOpen(!mobileMenuOpen)}
      >
        {mobileMenuOpen ? <X size={20} /> : <Menu size={20} />}
      </button>
      <div className={`hidden lg:hidden ${mobileMenuOpen ? 'block' : 'hidden'} absolute top-14 right-0 bg-indigo-600 p-4 shadow-md w-44`}>
        <Link to="/about" className="hover:text-indigo-700 transition-colors duration-200 block py-2">About</Link>
        <Link to="/packages" className="hover:text-indigo-700 transition-colors duration-200 block py-2">Packages</Link>
        <Link to="/book-now" className="bg-indigo-700 hover:bg-indigo-900 transition-colors duration-200 text-white block py-2 px-4 rounded-md">Book Now</Link>
      </div>
    </nav>
  );
}

